description:
Implement the full React frontend. The UI is intentionally simple: upload form, progress display, results panel. No auth, no routing, single page.

Reference: architecture.md §9, api-interfaces.md §5 and §7-8, technology-stack.md §4.

The scaffolded files from task-1 (types/api.ts, api/client.ts) are already complete. The hooks and components need full implementation.

---

## 1. `frontend/src/hooks/useAnalysis.ts`

Full implementation of the polling hook as specified in api-interfaces.md §5:

```typescript
export function useAnalysis() {
  const [jobId, setJobId] = useState<string | null>(null);
  const [pollStartedAt, setPollStartedAt] = useState<number | null>(null);

  const submitMutation = useMutation<AnalyzeResponse, ApiError, FormData>({
    mutationFn: (formData) => apiClient.submitAnalysis(formData),
    onSuccess: (data) => {
      setJobId(data.job_id);
      setPollStartedAt(Date.now());
    },
  });

  const statusQuery = useQuery<JobStatusResponse, ApiError>({
    queryKey: ['job-status', jobId],
    queryFn: () => apiClient.getJobStatus(jobId!),
    enabled: !!jobId,
    refetchInterval: (query) => {
      const status = query.state.data?.status;
      if (!status) return 2000;
      if (TERMINAL_STATUSES.includes(status)) return false;
      const elapsed = pollStartedAt ? Date.now() - pollStartedAt : 0;
      if (elapsed > 90_000) return false;
      return 2000;
    },
  });

  const reset = () => {
    setJobId(null);
    setPollStartedAt(null);
  };

  return { submitMutation, statusQuery, jobId, reset };
}
```

